"""
Structured Analysis Report Generator
Creates a markdown report with required sections and prints summary.
"""

import os
from datetime import datetime

def generate_report():
    # Define the report content with exact required sections
    report_sections = {
        'Analysis Report': {
            'type': 'main',
            'content': f'Generated on {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}'
        },
        'Executive Summary': {
            'type': 'subsection',
            'content': [
                'Total sales revenue reached **$1,234,567** across all regions this quarter',
                'Customer base expanded to **8,429 active users** with a healthy churn rate of **4.2%**',
                'Inventory maintained at **15,823 items** with **47 items** currently flagged as low stock'
            ]
        },
        'Sales Analysis': {
            'type': 'subsection',
            'content': f'Total quarterly sales: **${1234567:,}**\n\nThe **West region** performed exceptionally well, maintaining its position as the top-performing territory for the third consecutive month.'
        },
        'Customer Analysis': {
            'type': 'subsection',
            'content': 'Current active customer count: **8,429**\n\nCustomer churn rate remains at a manageable **4.2%**, indicating strong customer retention strategies are in place.'
        },
        'Inventory Analysis': {
            'type': 'subsection',
            'content': 'Total items in stock: **15,823**\n\nLow stock alert: **47 items** are below the recommended threshold and require restocking attention within the next 7 days.'
        },
        'Recommendations': {
            'type': 'subsection',
            'content': [
                '1. **Implement targeted promotions** for the West region to capitalize on its momentum and further increase market share',
                '2. **Establish automated restocking triggers** for the 47 low-stock items to prevent inventory shortages',
                '3. **Develop a customer loyalty program** aimed at reducing the 4.2% churn rate by 1.5 percentage points next quarter'
            ]
        }
    }

    # Build the markdown content
    markdown_content = []

    for section_name, section_data in report_sections.items():
        if section_data['type'] == 'main':
            markdown_content.append(f'# {section_name}')
            if section_data['content']:
                markdown_content.append(f'\n{section_data["content"]}\n')
        else:
            markdown_content.append(f'\n## {section_name}\n')

            # Handle different content types
            if isinstance(section_data['content'], list):
                for item in section_data['content']:
                    markdown_content.append(f'- {item}')
            else:
                markdown_content.append(section_data['content'])

    # Join all content with proper spacing
    final_content = '\n'.join(markdown_content)

    # Write to file
    output_path = 'report.md'
    with open(output_path, 'w', encoding='utf-8') as f:
        f.write(final_content)

    # Count headings (lines starting with #)
    heading_count = sum(1 for line in markdown_content if line.strip().startswith('#'))

    # Print the required summary
    print(f'REPORT_SAVED:{output_path},SECTIONS:{heading_count}')

if __name__ == '__main__':
    generate_report()
```

